import collections, collections.abc
class _DefaultSize(dict):
    def __missing__(self, key): return 1
class Cache(collections.abc.MutableMapping):
    __marker = object()
    def __init__(self, maxsize, getsizeof=None):
        self._data = {}
        self._size = _DefaultSize()
        self._currsize = 0
        self._maxsize = maxsize
        self._getsizeof = getsizeof if getsizeof is not None else type(self).getsizeof
    def __setitem__(self, key, value):
        size = self.getsizeof(value)
        if key in self._data: self._currsize -= self._size.pop(key)
        while self._currsize + size > self._maxsize: self.popitem()
        self._data[key] = value
        self._size[key] = size
        self._currsize += size
    def __delitem__(self, key):
        del self._data[key]
        print('popping', key, self._size, self._size.get(key), self._size.pop(key) if key in self._size else None)
        self._currsize -= self._size.pop(key)
    def __getitem__(self, key): return self._data[key]
    def __iter__(self): return iter(self._data)
    def __len__(self): return len(self._data)
    def getsizeof(self,v): return self._getsizeof(v)
    def popitem(self):
        key=next(iter(self._data))
        return key, self.pop(key)
    def pop(self, key, default=__marker):
        if key in self._data:
            v=self._data[key]
            del self[key]
            return v
        if default is self.__marker: raise KeyError(key)
        return default
